if (ack_num == conn->snd_una) {
if (++conn->dup_ack_cnt == 3) {
tcp_enter_fast_retransmit(conn);
} else if (conn->dup_ack_cnt > 3) {
conn->cwnd += MSS; // Window inflation
tcp_send_more(conn);
}
}

c
if (ack_num > conn->recover_seq) {
conn->cwnd = conn->ssthresh;
conn->dup_ack_cnt = 0;
conn->in_fast_recovery = false;
}
